    /* ──────────────────────────────────────────
     | 2. إدراج المعاملات
     ────────────────────────────────────────── */
    private function insertTransactions(): void
    {
        $rows = $this->transactionData();
        $now  = now()->toDateTimeString();
        $batch = [];
        $inserted = 0;
        $total = count($rows);

        foreach ($rows as $i => $r) {
            $cbId = $this->cbMap[$r['cashbox_code']] ?? null;
            if (!$cbId) {
                $this->command->warn("  ⚠️  صندوق غير موجود: {$r['cashbox_code']}");
                continue;
            }

            $row = [
                'cashbox_id'             => $cbId,
                'trx_date'               => $r['trx_date'],
                'type'                   => $r['type'],
                'amount'                 => $r['amount'],
                'currency'               => $r['currency'],
                'category'               => $r['category'] ?? null,
                'sub_category'           => $r['sub_category'] ?? null,
                'foreign_currency'       => $r['foreign_currency'] ?? null,
                'foreign_amount'         => $r['foreign_amount'] ?? null,
                'reference'              => $r['reference'] ?? null,
                'notes'                  => $r['notes'] ?? null,
                'status'                 => $r['status'] ?? 'posted',
                'posted_at'              => $r['posted_at'] ?? $r['trx_date'] . ' 12:00:00',
                'attachment_path'        => null,
                'to_cashbox_id'          => isset($r['to_cashbox_code'])   ? ($this->cbMap[$r['to_cashbox_code']] ?? null)   : null,
                'exchange_to_cashbox_id' => isset($r['exchange_to_cashbox_code']) ? ($this->cbMap[$r['exchange_to_cashbox_code']] ?? null) : null,
                'created_at'             => $now,
                'updated_at'             => $now,
            ];

            $batch[] = $row;

            if (count($batch) >= 100) {
                CashboxTransaction::insert($batch);
                $inserted += count($batch);
                $batch = [];
                $pct = round(($i + 1) / $total * 100);
                $this->command->line("  ⏳ {$pct}% ({$inserted}/{$total})");
            }
        }

        if (!empty($batch)) {
            CashboxTransaction::insert($batch);
            $inserted += count($batch);
        }

        $this->command->info("  ✅ تم إدراج {$inserted} معاملة");
    }

